[ExtensionOf(classStr(SalesCopyingContract))]
final class FWFTextBlockSalesCopyingContract_Extension
{
    private NoYes   copyHeaderTB;
    private NoYes   copyLineTB;

    #define.CurrentVersion(1)
    #localmacro.CurrentList
        copyHeaderTB,
        copyLineTB
    #endmacro

}

Method.Source:
public NoYes parmCopyHeaderTextBlock(NoYes _copyHeaderTB = copyHeaderTB)
{
    copyHeaderTB = _copyHeaderTB;
    return copyHeaderTB;
}

public NoYes parmCopyLineTextBlock(NoYes _copyLineTB = copyLineTB)
{
    copyLineTB = _copyLineTB;
    return copyLineTB;
}

public container pack()
{
    container packedClass = next pack();
    return SysPackExtensions::appendExtension(packedClass, classStr(FWFTextBlockSalesCopyingContract_Extension), this.packExtension());
}

public boolean unpack(container _packedClass)
{
    boolean result = next unpack(_packedClass);

    if (result)
    {
        container packedClassExtension = SysPackExtensions::findExtension(_packedClass, classStr(FWFTextBlockSalesCopyingContract_Extension));

        if (!this.unpackExtension(packedClassExtension))
        {
            result = false;
        }
    }

    return result;
}

private boolean unpackExtension(container _packedClass)
{
    Integer version = RunBase::getVersion(_packedClass);

    switch (version)
    {
        case #CurrentVersion:
            [version, #currentList] = _packedClass;
            break;
        default:
            return false;
    }
    return true;
}
